import React, { useState, useEffect } from 'react';
import {
  Box,
  Paper,
  TextField,
  Button,
  Typography,
  Link,
  Alert,
  CircularProgress,
  Container,
  InputAdornment,
  IconButton
} from '@mui/material';
import {
  Visibility,
  VisibilityOff,
  Email,
  Lock,
  Instagram,
  YouTube,
  Telegram as TelegramIcon // Renomeando para evitar conflito se houver outro Telegram
} from '@mui/icons-material';
import { Link as RouterLink } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../../contexts/AuthContext';



const Login = () => {
  const { login } = useAuth();
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [videoLoaded, setVideoLoaded] = useState(false);

  const fullText = 'Nautilus Automação';

  // useEffect da animação de digitação removido.



  // Removido - não precisamos mais da animação de fundo



  // Removido - não precisamos mais da animação de fundo

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
    // Limpar erro quando o usuário começar a digitar
    if (error) setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    // Validação básica
    if (!formData.email || !formData.password) {
      setError('Todos os campos são obrigatórios');
      setLoading(false);
      return;
    }

    // Validação simples de email
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(formData.email)) {
      setError('Formato de email inválido');
      setLoading(false);
      return;
    }

    try {
      const result = await login(formData.email, formData.password);

      if (result.success) {
        toast.success('Login realizado com sucesso!');
      } else {
        setError(result.message || 'Erro ao fazer login');
        toast.error(result.message || 'Erro ao fazer login');
      }
    } catch (error) {
      console.error('Erro no login:', error);
      setError('Erro ao fazer login. Tente novamente.');
      toast.error('Erro ao fazer login');
    } finally {
      setLoading(false);
    }
  };

  const togglePasswordVisibility = () => {
    setShowPassword(!showPassword);
  };

  return (
    <Box
      sx={{
        minHeight: '100vh',
        background: '#000000', // Fundo preto
        position: 'relative',
        overflow: 'hidden',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        padding: 2
      }}
    >
      {/* Placeholder de fundo enquanto o vídeo carrega */}
      {!videoLoaded && (
        <Box
          sx={{
            position: 'absolute',
            top: 0,
            left: 0,
            width: '100vw',
            height: '100vh',
            zIndex: 0,
            background: 'linear-gradient(135deg, #0c0c0c 0%, #1a1a1a 25%, #2d2d2d 50%, #1a1a1a 75%, #0c0c0c 100%)',
            backgroundSize: '400% 400%',
            animation: 'gradientShift 8s ease-in-out infinite'
          }}
        />
      )}

      {/* Vídeo de fundo do Vimeo */}
      <Box
        sx={{
          position: 'absolute',
          top: 0,
          left: 0,
          width: '100vw',
          height: '100vh',
          zIndex: 0,
          overflow: 'hidden',
          opacity: videoLoaded ? 1 : 0,
          transition: 'opacity 1s ease-in-out',
          '& iframe': {
            position: 'absolute',
            top: '50%',
            left: '50%',
            width: '100vw',
            height: '56.25vw', // 16:9 aspect ratio
            minHeight: '100vh',
            minWidth: '177.78vh', // 16:9 aspect ratio
            transform: 'translate(-50%, -50%)',
            border: 'none',
            objectFit: 'cover'
          }
        }}
      >
        <iframe
          src="https://player.vimeo.com/video/1093368764?share=copy&autoplay=1&loop=1&muted=1&background=1&controls=0#t=0"
          width="100%"
          height="100%"
          frameBorder="0"
          allow="autoplay; fullscreen; picture-in-picture"
          allowFullScreen
          title="Background Video"
          onLoad={() => {
            setVideoLoaded(true);
          }}
        />
      </Box>

      {/* Overlay escuro para melhor legibilidade */}
      <Box
        sx={{
          position: 'absolute',
          top: 0,
          left: 0,
          width: '100%',
          height: '100%',
          backgroundColor: 'rgba(0, 0, 0, 0.5)',
          zIndex: 1
        }}
      />



      {/* CSS para animações */}
      <style>
        {`
          @keyframes gradientShift {
            0% {
              background-position: 0% 50%;
            }
            50% {
              background-position: 100% 50%;
            }
            100% {
              background-position: 0% 50%;
            }
          }

          @keyframes blink {
            0%, 50% { opacity: 1; }
            51%, 100% { opacity: 0; }
          }
          @keyframes blinkDots {
            0%, 33% { opacity: 1; }
            34%, 66% { opacity: 0.5; }
            67%, 100% { opacity: 0; }
          }
          @keyframes shimmer {
            0% {
              background-position: -200% 0;
            }
            100% {
              background-position: 200% 0;
            }
          }
          @keyframes float {
            0%, 100% { transform: translateY(0px) rotate(0deg); }
            50% { transform: translateY(-10px) rotate(180deg); }
          }
          @keyframes glow {
            0%, 100% { text-shadow: 0 0 5px currentColor; }
            50% { text-shadow: 0 0 20px currentColor, 0 0 30px currentColor; }
          }
        `}
      </style>




      {/* Cartão de Crédito */}
      <Box
        sx={{
          width: '100%',
          maxWidth: 500,
          height: 'auto', // Altura automática para acomodar o conteúdo
          minHeight: 420, // Altura mínima para garantir espaço
          background: 'linear-gradient(135deg, rgba(192, 192, 192, 0.1) 0%, rgba(169, 169, 169, 0.05) 100%)',
          borderRadius: '20px',
          border: '1px solid rgba(192, 192, 192, 0.3)',
          backdropFilter: 'blur(20px)',
          position: 'relative',
          overflow: 'hidden',
          boxShadow: '0 8px 32px rgba(0, 0, 0, 0.3), inset 0 1px 0 rgba(255, 255, 255, 0.1)',
          zIndex: 2, // Garante que o cartão fique acima dos símbolos
          '&::before': {
            content: '""',
            position: 'absolute',
            top: 0,
            left: '-100%',
            width: '100%',
            height: '100%',
            background: 'linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.1), transparent)',
            animation: 'shimmer 3s infinite'
          }
        }}
      >
        {/* Chip do cartão removido */}

        {/* Logo/Marca removido */}

        {/* Área do formulário */}
        <Typography
          variant="h4" // Ajustado para h4 para caber melhor no modal
          component="h1"
          sx={{
            fontWeight: 'bold',
            color: '#FFFFFF', // Alterado para branco
            textAlign: 'center',
            fontFamily: '"Courier New", Courier, monospace',
            letterSpacing: '1.5px',
            zIndex: 3,
            minHeight: '40px', // Ajuste para o novo tamanho
            // textShadow removido
            paddingTop: 2, // Espaçamento no topo dentro do modal
            paddingBottom: 1, // Espaçamento abaixo do título
            width: '100%' // Ocupa a largura do container do formulário
            // Animação de cursor removida
          }}
        >
          {fullText} 
        </Typography>
       <Box
          sx={{
            position: 'absolute',
            bottom: 0,
            left: 0,
            right: 0,
            padding: 4,
            background: 'rgba(0, 0, 0, 0.2)',
            // borderTop: '1px solid rgba(192, 192, 192, 0.2)', // Removido para eliminar a linha
            minHeight: '300px' // Ajustado para garantir espaço para o formulário
          }}
        >
          <Box component="form" onSubmit={handleSubmit}>
            {/* Título do cartão foi removido daqui e substituído pelo animado acima */}
              {error && (
                <Alert 
                  severity="error" 
                  sx={{ 
                    mb: 3,
                    backgroundColor: 'rgba(211, 47, 47, 0.1)',
                    color: '#ff6b6b',
                    border: '1px solid rgba(211, 47, 47, 0.3)',
                    '& .MuiAlert-icon': {
                      color: '#ff6b6b'
                    }
                  }}
                >
                  {error}
                </Alert>
              )}

              <TextField
                fullWidth
                name="email"
                label="USUÁRIO"
                type="email"
                value={formData.email}
                onChange={handleChange}
                margin="normal"
                required
                autoComplete="email"
                autoFocus
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Email sx={{ color: '#C0C0C0' }} />
                    </InputAdornment>
                  ),
                }}
                sx={{
                  '& .MuiOutlinedInput-root': {
                    backgroundColor: 'rgba(192, 192, 192, 0.05)',
                    border: '1px solid rgba(192, 192, 192, 0.3)',
                    borderRadius: '8px',
                    color: '#C0C0C0',
                    '& fieldset': {
                      border: 'none'
                    },
                    '&:hover': {
                      backgroundColor: 'rgba(192, 192, 192, 0.1)',
                      border: '1px solid rgba(192, 192, 192, 0.5)'
                    },
                    '&.Mui-focused': {
                      backgroundColor: 'rgba(192, 192, 192, 0.1)',
                      border: '1px solid #C0C0C0'
                    }
                  },
                  '& .MuiInputLabel-root': {
                    color: '#A9A9A9',
                    fontSize: '1rem',
                    fontWeight: 'bold',
                    letterSpacing: '1px'
                  },
                  '& .MuiInputLabel-root.Mui-focused': {
                    color: '#C0C0C0'
                  }
                }}
              />

              <TextField
                fullWidth
                name="password"
                label="SENHA"
                type={showPassword ? 'text' : 'password'}
                value={formData.password}
                onChange={handleChange}
                margin="normal"
                required
                autoComplete="current-password"
                InputProps={{
                  startAdornment: (
                    <InputAdornment position="start">
                      <Lock sx={{ color: '#C0C0C0' }} />
                    </InputAdornment>
                  ),
                  endAdornment: (
                    <InputAdornment position="end">
                      <IconButton
                        onClick={togglePasswordVisibility}
                        edge="end"
                        aria-label="toggle password visibility"
                        sx={{ color: '#C0C0C0' }}
                      >
                        {showPassword ? <VisibilityOff /> : <Visibility />}
                      </IconButton>
                    </InputAdornment>
                  ),
                }}
                sx={{
                  '& .MuiOutlinedInput-root': {
                    backgroundColor: 'rgba(192, 192, 192, 0.05)',
                    border: '1px solid rgba(192, 192, 192, 0.3)',
                    borderRadius: '8px',
                    color: '#C0C0C0',
                    '& fieldset': {
                      border: 'none'
                    },
                    '&:hover': {
                      backgroundColor: 'rgba(192, 192, 192, 0.1)',
                      border: '1px solid rgba(192, 192, 192, 0.5)'
                    },
                    '&.Mui-focused': {
                      backgroundColor: 'rgba(192, 192, 192, 0.1)',
                      border: '1px solid #C0C0C0'
                    }
                  },
                  '& .MuiInputLabel-root': {
                    color: '#A9A9A9',
                    fontSize: '1rem',
                    fontWeight: 'bold',
                    letterSpacing: '1px'
                  },
                  '& .MuiInputLabel-root.Mui-focused': {
                    color: '#C0C0C0'
                  }
                }}
              />

              <Button
                type="submit"
                fullWidth
                variant="contained"
                disabled={loading}
                sx={{
                  mt: 2,
                  mb: 1,
                  py: 1,
                  fontSize: '1.125rem',
                  fontWeight: 'bold',
                  textTransform: 'uppercase',
                  letterSpacing: '1px',
                  background: 'linear-gradient(135deg, rgba(192, 192, 192, 0.2), rgba(169, 169, 169, 0.1))',
                  color: '#C0C0C0',
                  border: '1px solid rgba(192, 192, 192, 0.3)',
                  borderRadius: '8px',
                  backdropFilter: 'blur(10px)',
                  '&:hover': {
                    background: 'linear-gradient(135deg, rgba(192, 192, 192, 0.3), rgba(169, 169, 169, 0.2))',
                    border: '1px solid rgba(192, 192, 192, 0.5)',
                  },
                  '&:disabled': {
                    background: 'rgba(192, 192, 192, 0.05)',
                    color: 'rgba(192, 192, 192, 0.3)',
                  },
                }}
              >
                {loading ? (
                  <CircularProgress size={20} sx={{ color: '#C0C0C0' }} />
                ) : (
                  'ACESSAR'
                )}
              </Button>

              {/* Divisor */}
              <Box sx={{ display: 'flex', alignItems: 'center', my: 3 }}>
                <Box sx={{ flex: 1, height: '1px', background: 'rgba(192, 192, 192, 0.3)' }} />
                <Typography sx={{ px: 2, color: '#A9A9A9', fontSize: '0.8rem' }}>OU</Typography>
                <Box sx={{ flex: 1, height: '1px', background: 'rgba(192, 192, 192, 0.3)' }} />
              </Box>

              {/* Seção para Usuários Existentes */}
              <Box sx={{ textAlign: 'center', mb: 3 }}>
                <Typography 
                  variant="body2" 
                  sx={{ 
                    color: '#A9A9A9',
                    fontSize: '0.9rem',
                    mb: 2
                  }}
                >
                  Já tem acesso? Faça login com suas credenciais:
                </Typography>

                <Button
                  component={RouterLink}
                  to="/dashboard"
                  fullWidth
                  variant="outlined"
                  sx={{
                    py: 1.5,
                    fontSize: '1rem',
                    fontWeight: 'bold',
                    textTransform: 'uppercase',
                    letterSpacing: '1px',
                    color: '#C0C0C0',
                    border: '1px solid rgba(192, 192, 192, 0.3)',
                    borderRadius: '8px',
                    '&:hover': {
                      border: '1px solid rgba(192, 192, 192, 0.5)',
                      backgroundColor: 'rgba(192, 192, 192, 0.1)',
                    },
                  }}
                >
                  ENTRAR NO SISTEMA
                </Button>
              </Box>

              {/* Divisor */}
              <Box sx={{ display: 'flex', alignItems: 'center', my: 3 }}>
                <Box sx={{ flex: 1, height: '1px', background: 'rgba(192, 192, 192, 0.3)' }} />
                <Typography sx={{ px: 2, color: '#A9A9A9', fontSize: '0.8rem' }}>NOVO USUÁRIO</Typography>
                <Box sx={{ flex: 1, height: '1px', background: 'rgba(192, 192, 192, 0.3)' }} />
              </Box>

              {/* Seção de Pagamento e Registro */}
              <Box sx={{ textAlign: 'center', mt: 2 }}>
                <Typography 
                  variant="body2" 
                  sx={{ 
                    color: '#A9A9A9',
                    fontSize: '0.9rem',
                    mb: 2
                  }}
                >
                  Para se cadastrar, você precisa assinar ou recarregar sua conta:
                </Typography>

                {/* Botão de Assinatura */}
                <Button
                  fullWidth
                  variant="contained"
                  onClick={() => window.open('https://pay.hub.la/tmF5YtOlGb1GDVFSam7S', '_blank')}
                  sx={{
                    mb: 2,
                    py: 1.5,
                    fontSize: '1rem',
                    fontWeight: 'bold',
                    textTransform: 'uppercase',
                    letterSpacing: '1px',
                    background: 'linear-gradient(135deg, #4CAF50, #45a049)',
                    color: '#FFFFFF',
                    borderRadius: '8px',
                    '&:hover': {
                      background: 'linear-gradient(135deg, #45a049, #3d8b40)',
                    },
                  }}
                >
                  ASSINAR PLANO
                </Button>

                <Typography 
                  variant="body2" 
                  sx={{ 
                    color: '#A9A9A9',
                    fontSize: '0.9rem',
                    mb: 1
                  }}
                >
                  Ou recarregue sua conta:
                </Typography>

                {/* Opções de Recarga */}
                <Box sx={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 1, mb: 2 }}>
                  <Button
                    variant="outlined"
                    onClick={() => window.open('https://pay.hub.la/MdORdaFcTzWvhT9IkZHP', '_blank')}
                    sx={{
                      py: 1,
                      fontSize: '0.9rem',
                      fontWeight: 'bold',
                      color: '#C0C0C0',
                      border: '1px solid rgba(192, 192, 192, 0.3)',
                      '&:hover': {
                        border: '1px solid rgba(192, 192, 192, 0.5)',
                        backgroundColor: 'rgba(192, 192, 192, 0.1)',
                      },
                    }}
                  >
                    R$ 50
                  </Button>
                  <Button
                    variant="outlined"
                    onClick={() => window.open('https://pay.hub.la/mFfwQbUAqILTw8bfDXjo', '_blank')}
                    sx={{
                      py: 1,
                      fontSize: '0.9rem',
                      fontWeight: 'bold',
                      color: '#C0C0C0',
                      border: '1px solid rgba(192, 192, 192, 0.3)',
                      '&:hover': {
                        border: '1px solid rgba(192, 192, 192, 0.5)',
                        backgroundColor: 'rgba(192, 192, 192, 0.1)',
                      },
                    }}
                  >
                    R$ 100
                  </Button>
                  <Button
                    variant="outlined"
                    onClick={() => window.open('https://pay.hub.la/EVrxnuDyf4JeB0uIYaFC', '_blank')}
                    sx={{
                      py: 1,
                      fontSize: '0.9rem',
                      fontWeight: 'bold',
                      color: '#C0C0C0',
                      border: '1px solid rgba(192, 192, 192, 0.3)',
                      '&:hover': {
                        border: '1px solid rgba(192, 192, 192, 0.5)',
                        backgroundColor: 'rgba(192, 192, 192, 0.1)',
                      },
                    }}
                  >
                    R$ 200
                  </Button>
                  <Button
                    variant="outlined"
                    onClick={() => window.open('https://pay.hub.la/LmFhy6R6HP3fjoJxZe5z', '_blank')}
                    sx={{
                      py: 1,
                      fontSize: '0.9rem',
                      fontWeight: 'bold',
                      color: '#C0C0C0',
                      border: '1px solid rgba(192, 192, 192, 0.3)',
                      '&:hover': {
                        border: '1px solid rgba(192, 192, 192, 0.5)',
                        backgroundColor: 'rgba(192, 192, 192, 0.1)',
                      },
                    }}
                  >
                    R$ 500
                  </Button>
                </Box>

                <Typography 
                  variant="body2" 
                  sx={{ 
                    color: '#A9A9A9',
                    fontSize: '0.8rem',
                    fontStyle: 'italic'
                  }}
                >
                  Após o pagamento, você receberá acesso para se cadastrar.
                </Typography>
              </Box>

              {/* Ícones de Redes Sociais */}
              <Box sx={{ textAlign: 'center', mt: 2, mb: -2 }}>
                <IconButton 
                  aria-label="Instagram" 
                  component="a" 
                  href="https://www.instagram.com/bigwhale_oficial?igsh=MXh6aHVjZWtyY240YQ==" 
                  target="_blank" 
                  rel="noopener noreferrer"
                  sx={{ color: 'rgba(192, 192, 192, 0.7)', '&:hover': { color: '#C0C0C0' } }}
                >
                  <Instagram />
                </IconButton>
                <IconButton 
                  aria-label="YouTube" 
                  component="a" 
                  href="https://www.youtube.com/@grupobigwhale_of" 
                  target="_blank" 
                  rel="noopener noreferrer"
                  sx={{ color: 'rgba(192, 192, 192, 0.7)', '&:hover': { color: '#C0C0C0' } }}
                >
                  <YouTube />
                </IconButton>
                <IconButton 
